def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
        else:
            score = 0
            for _ in range(3):
                if ratio < 0.1:
                    score += (0.1 - ratio) ** 2
                elif ratio < 0.5:
                    score += (0.5 - ratio) * 0.5
                else:
                    score += np.log1p(ratio)
                ratio = np.sqrt(ratio)
            priorities[i] = score
    max_priority = np.max(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 1
    return priorities
